using ExtendedExceptions;namespace Core.Gameplay.Power{    public sealed class DuplicatePowerIdException : ExtendedException    {        public DuplicatePowerIdException(string powerId)            : base("power-1", $"Duplicate power id '{powerId}'") { }    }    public sealed class EntityPowerNotFoundException : ExtendedException    {        public EntityPowerNotFoundException(string powerId)            : base("power-2", $"Entity power not found for id '{powerId}'") { }    }    public sealed class HeroPowerIdNotFoundException : ExtendedException    {        public HeroPowerIdNotFoundException(string heroPowerId)            : base("power-3", $"Hero power id '{heroPowerId}' is not registered") { }    }    public sealed class InvalidEntityPowerProviderException : ExtendedException    {        public InvalidEntityPowerProviderException(string providerName, string reason)            : base("power-4", $"Invalid entity power provider '{providerName}': {reason}") { }    }}